INSERT INTO workout (workout_date, created_by, modified_by, created_on, modified_on) SELECT DATE '2026-05-01', NULL, NULL, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP WHERE NOT EXISTS (SELECT 1 FROM workout WHERE workout_date = DATE '2026-05-01'); INSERT INTO workout_set (exercise, repetitions, body_part, weight, line_order, workout_id, status) SELECT v.exercise, v.repetitions, v.body_part, v.weight, v.line_order, w.id, 'DONE' FROM workout w CROSS JOIN (VALUES ('Hantle curl', 12, 'arms', 12.0, 0), ('Hantle curl', 10, 'arms', 14.0, 1), ('Prostowanie na maszynie', 12, 'arms', 22.5, 2) ) AS v(exercise, repetitions, body_part, weight, line_order) WHERE w.workout_date = DATE '2026-05-01' AND NOT EXISTS (SELECT 1 FROM workout_set s WHERE s.workout_id = w.id);
